      D_1&:
 \mathopen {}\left \lvert C\right \rvert \mathclose {}
\to  
 \mathopen {}\left \lvert C\right \rvert \mathclose {}
\to \mathsf {Set}\\
      F_1&: D_1 = \lambda {x,y}\mathpunct {.}{C
 \mathopen {}\left \lparen x,y\right \rparen \mathclose {}
}
    \end {aligned}

